import{_ as t,o as i,c as a,a3 as o}from"./chunks/framework.CjquFG0V.js";const m=JSON.parse('{"title":"72. Amenities And Facilities","description":"","frontmatter":{"title":"72. Amenities And Facilities","eba":"Doctors in Training 2022-2026","topics":["accommodation"]},"headers":[],"relativePath":"ebas/doctors-in-training/accommodation/72-amenities-and-facilities.md","filePath":"ebas/doctors-in-training/accommodation/72-amenities-and-facilities.md"}'),n={name:"ebas/doctors-in-training/accommodation/72-amenities-and-facilities.md"};function s(r,e,c,l,d,p){return i(),a("div",null,[...e[0]||(e[0]=[o('<h1 id="_72-amenities-and-facilities" tabindex="-1">72. Amenities And Facilities <a class="header-anchor" href="#_72-amenities-and-facilities" aria-label="Permalink to &quot;72. Amenities And Facilities&quot;">​</a></h1><p><strong>72.1</strong> Amenities</p><p>The Health Service must provide Doctors access to the following amenities:</p><p><strong>(a)</strong> a changing room with securable storage;</p><p><strong>(b)</strong> a common room; and</p><p><strong>(c)</strong> a shower and bathroom.</p><p><strong>72.2</strong> Facilities</p><p>Health Services should provide Doctors access to the following facilities:</p><p><strong>(a)</strong> access to workstations, telecommunication and information technology capable of ensuring administrative and similar work can be accomplished efficiently;</p><p><strong>(b)</strong> access to internet and e-mail facilities for work purposes;</p><p><strong>(c)</strong> 24-hour access to a library and all of its resources;</p><p><strong>(d)</strong> access to a security escort at night;</p><p><strong>(e)</strong> reserved car parking paid for by the Health Service and available for a Doctor when rostered on-call and when recalled to duty. The parking spaces must be well lit and in a secure place within 200 meters from the main entrance of the Health Service; and</p><p><strong>(f)</strong> an office available for private discussion with patients’ relatives.</p><p><strong>72.3</strong> In the case where a Health Service does not meet the standards described in subclause 72.2 above, the Health Service, the Department and the Association will consult to determine a time-frame within which the facilities will be provided within available capital funding budgets.</p><p><strong>72.4</strong> Additional Amenities and Facilities for Doctors working overnight</p><p>Where a Doctor is rostered for a period of 12 hours or more commencing after 6.00 p.m., the Health Service must make available to the Doctor for the period of duty:</p><p><strong>(a)</strong> a separate reasonably furnished bedroom with adequate heating and cooling facilities, including a study desk, chair and study light;</p><p><strong>(b)</strong> reasonable provision for the preparation of light refreshments by the Doctor;</p><p><strong>(c)</strong> reasonable provision for laundering, drying and ironing of personal clothing by the Doctor; and</p><p><strong>(d)</strong> rooms fully cleaned and beds made.</p><p>Plain language terms: amenities, facilities.</p>',22)])])}const h=t(n,[["render",s]]);export{m as __pageData,h as default};
